use crate::models::Claims;
use chrono::Utc;
use hmac::{Hmac, Mac};
use sha2::Sha256;

type HmacSha256 = Hmac<Sha256>;

const SESSION_DURATION_HOURS: i64 = 12;

pub fn create_token(
    user_id: &str,
    username: &str,
    role: &str,
    store_id: Option<&str>,
    secret: &str,
) -> String {
    let now = Utc::now().timestamp();
    let claims = Claims {
        user_id: user_id.to_string(),
        username: username.to_string(),
        role: role.to_string(),
        store_id: store_id.map(String::from),
        iat: now,
        exp: now + (SESSION_DURATION_HOURS * 3600),
    };

    let payload = serde_json::to_string(&claims).unwrap();
    let payload_b64 = base64::Engine::encode(&base64::engine::general_purpose::URL_SAFE_NO_PAD, &payload);

    let mut mac = HmacSha256::new_from_slice(secret.as_bytes()).unwrap();
    mac.update(payload_b64.as_bytes());
    let signature = hex::encode(mac.finalize().into_bytes());

    format!("{}.{}", payload_b64, signature)
}

pub fn validate_token(token: &str, secret: &str) -> Option<Claims> {
    let parts: Vec<&str> = token.splitn(2, '.').collect();
    if parts.len() != 2 {
        return None;
    }

    let payload_b64 = parts[0];
    let signature = parts[1];

    let mut mac = HmacSha256::new_from_slice(secret.as_bytes()).ok()?;
    mac.update(payload_b64.as_bytes());
    let expected = hex::encode(mac.finalize().into_bytes());

    if signature != expected {
        return None;
    }

    let payload_bytes = base64::Engine::decode(
        &base64::engine::general_purpose::URL_SAFE_NO_PAD,
        payload_b64,
    ).ok()?;
    let claims: Claims = serde_json::from_slice(&payload_bytes).ok()?;

    let now = Utc::now().timestamp();
    if claims.exp < now {
        return None;
    }

    Some(claims)
}

