    let reservation_id = uuid::Uuid::new_v4().to_string();
    conn.execute(
        "INSERT INTO reservations (id, asset_type, asset_id, store_id, user_id, start_time, end_time, status) VALUES (?1, ?2, ?3, ?4, ?5, ?6, ?7, 'confirmed')",
        rusqlite::params![reservation_id, req.asset_type, req.asset_id, req.store_id, user_id, req.start_time, req.end_time],
    ).map_err(|_| {
