    );

    let reservation = Reservation {
        id: reservation_id,
        asset_type: req.asset_type.clone(),
        asset_id: req.asset_id.clone(),
        store_id: req.store_id.clone(),
        user_id: user_id.to_string(),
        start_time: req.start_time.clone(),
