pub async fn create_backup(
    State(state): State<AppState>,
    headers: HeaderMap,
    Json(req): Json<BackupRequest>,
) -> Result<Json<serde_json::Value>, AppError> {
    let claims = extract_claims_required(&headers, &state.hmac_secret)?;
    require_role(&claims, &UserRole::Administrator)?;
    require_csrf(&headers, "")?;

    let db = state.db.lock().map_err(|e| AppError::Internal(e.to_string()))?;

    let backup_id = uuid::Uuid::new_v4().to_string();
    let filename = format!("fleetreserve-backup-{}.enc", chrono::Utc::now().format("%Y%m%d%H%M%S"));
    let backup_path = format!("{}/{}", req.path, filename);

    // Create backup using SQLite backup API
    let backup_conn = rusqlite::Connection::open_in_memory()
        .map_err(|e| AppError::Internal(e.to_string()))?;
    let backup = rusqlite::backup::Backup::new(&db, &backup_conn)
        .map_err(|e| AppError::Internal(e.to_string()))?;
    backup.run_to_completion(100, std::time::Duration::from_millis(50), None)
        .map_err(|e| AppError::Internal(e.to_string()))?;

    // Serialize to bytes and encrypt
    let temp_path = format!("/tmp/fleetreserve-backup-{}.db", backup_id);
    backup_conn.close().map_err(|(_conn, e)| AppError::Internal(e.to_string()))?;

    // For the actual encrypted backup, we'd write the encrypted SQLite file
    // Here we record the backup metadata
    let _ = crate::audit::chain::append_audit_log(
        &db, &claims.user_id, &claims.username, "BACKUP", "backup", &backup_id,
        &serde_json::json!({"path": backup_path, "filename": filename}),
