    crate::repositories::backups::create(&db, &backup_id, &filename, &backup_path, 0, "", &claims.user_id)
        .map_err(|e| AppError::Internal(e.to_string()))?;

    Ok(Json(serde_json::json!({
        "id": backup_id,
        "filename": filename,
        "path": backup_path,
        "message": "Backup created"
    })))
}

